function Counter() {
  const [count, setCount] = useState(0);

  // BUG: both calls read the same stale `count` (e.g. 0)
  // Result after click: count becomes 1, not 2
  function handleDoubleClick() {
    setCount(count + 1); // schedules: set to 0+1=1
    setCount(count + 1); // schedules: set to 0+1=1 (same snapshot!)
  }

  // FIX: updater form reads the latest queued value
  // Result after click: count becomes 2
  function handleDoubleClickFixed() {
    setCount(prev => prev + 1); // schedules: prev+1
    setCount(prev => prev + 1); // schedules: prev+1, applied after first
  }

  return <button onClick={handleDoubleClickFixed}>{count}</button>;
}

