function AlertButton() {
  const [message, setMessage] = useState('Hello');

  function handleClick() {
    setMessage('Goodbye');
    // `message` is still 'Hello' here — the snapshot does not change
    alert(message); // alerts 'Hello', not 'Goodbye'
    // The button will SHOW 'Goodbye' after React re-renders,
    // but this handler will never see the new value
  }

  return <button onClick={handleClick}>Alert: {message}</button>;
}

function handleClick() {
  const newMessage = 'Goodbye';
  setMessage(newMessage);
  alert(newMessage); // alerts 'Goodbye' — from the local variable, not from state
}

