import { useState } from 'react';

let nextId = 1;

function TodoList() {
  const [todos, setTodos] = useState([]);
  const [text, setText] = useState('');

  function handleAdd() {
    if (!text.trim()) return;
    setTodos(prev => [
      ...prev,
      { id: nextId++, text: text.trim(), done: false },
    ]);
    setText('');
  }

  function handleToggle(id) {
    setTodos(prev =>
      prev.map(todo =>
        todo.id === id ? { ...todo, done: !todo.done } : todo
      )
    );
  }

  function handleDelete(id) {
    setTodos(prev => prev.filter(todo => todo.id !== id));
  }

  return (
    <div>
      <input
        value={text}
        onChange={e => setText(e.target.value)}
        onKeyDown={e => e.key === 'Enter' && handleAdd()}
        placeholder="New todo"
      />
      <button onClick={handleAdd}>Add</button>
      <ul>
        {todos.map(todo => (
          <li key={todo.id}>
            <input
              type="checkbox"
              checked={todo.done}
              onChange={() => handleToggle(todo.id)}
            />
            <span style={{ textDecoration: todo.done ? 'line-through' : 'none' }}>
              {todo.text}
            </span>
            <button onClick={() => handleDelete(todo.id)}>✕</button>
          </li>
        ))}
      </ul>
    </div>
  );
}

function Tracker() {
  const [a, setA] = useState(0);
  const [b, setB] = useState(0);

  let renderCount = 0;
  renderCount++; // increments each time React calls this function

  function handleBothAtOnce() {
    setA(1);
    setB(1);
    // One re-render: renderCount goes from 1 → 2
  }

  // If each setter were in a separate click handler,
  // clicking both would cause two re-renders.

  return (
    <div>
      <p>a={a}, b={b}</p>
      <button onClick={handleBothAtOnce}>Update both</button>
    </div>
  );
}

function NotificationPanel() {
  const [count, setCount] = useState(0);

  function handleClick() {
    // count is captured here — e.g. 0
    setTimeout(() => {
      // 2 seconds later, count may have changed to 5
      // but the callback still sees 0
      alert(`Count was ${count} when you clicked`);
      // If you NEED the latest value, use the updater form:
      setCount(latest => {
        alert(`Current count: ${latest}`);
        return latest + 1;
      });
    }, 2000);
  }

  return (
    <div>
      <p>Count: {count}</p>
      <button onClick={() => setCount(c => c + 1)}>+1</button>
      <button onClick={handleClick}>Alert after 2s</button>
    </div>
  );
}

import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import TodoList from './TodoList';

test('adds and removes todos', async () => {
  render(<TodoList />);

  // Add a todo
  const input = screen.getByPlaceholderText('New todo');
  await userEvent.type(input, 'Buy milk');
  await userEvent.click(screen.getByRole('button', { name: 'Add' }));

  expect(screen.getByText('Buy milk')).toBeInTheDocument();
  expect(input).toHaveValue(''); // text cleared after add

  // Toggle it
  await userEvent.click(screen.getByRole('checkbox'));
  expect(screen.getByText('Buy milk')).toHaveStyle('text-decoration: line-through');

  // Delete it
  await userEvent.click(screen.getByRole('button', { name: '✕' }));
  expect(screen.queryByText('Buy milk')).not.toBeInTheDocument();
});

function LikeButton({ postId, initialLikes }) {
  const [likes, setLikes] = useState(initialLikes);
  const [isLiked, setIsLiked] = useState(false);

  async function handleLike() {
    // Optimistically update UI immediately
    const newLiked = !isLiked;
    setIsLiked(newLiked);
    setLikes(prev => newLiked ? prev + 1 : prev - 1);

    try {
      await toggleLike(postId, newLiked);
    } catch {
      // Rollback on error
      setIsLiked(!newLiked);
      setLikes(prev => newLiked ? prev - 1 : prev + 1);
    }
  }

  return (
    <button onClick={handleLike}>
      {isLiked ? '♥' : '♡'} {likes}
    </button>
  );
}

